from fastapi import FastAPI

app = FastAPI()

# Resource: /books
books_db = {1: {"title": "1984", "author": "Orwell"}}

@app.get("/books")
def list_books():
    return list(books_db.values())       # GET collection

@app.get("/books/{book_id}")
def get_book(book_id: int):
    return books_db.get(book_id, {})     # GET single resource

@app.post("/books")
def create_book(title: str, author: str):
    new_id = max(books_db.keys()) + 1
    books_db[new_id] = {"title": title, "author": author}
    return books_db[new_id]              # POST create

@app.put("/books/{book_id}")
def update_book(book_id: int, title: str, author: str):
    books_db[book_id] = {"title": title, "author": author}
    return books_db[book_id]             # PUT replace

@app.delete("/books/{book_id}")
def delete_book(book_id: int):
    del books_db[book_id]
    return {"deleted": True}             # DELETE remove
