from fastapi import FastAPI, Depends, HTTPException
from fastapi.security import OAuth2PasswordBearer, APIKeyHeader
from jose import jwt, JWTError
from datetime import datetime, timedelta

app = FastAPI()
SECRET = "super-secret-key"

# API Key auth
api_key_header = APIKeyHeader(name="X-API-Key")
def verify_api_key(key: str = Depends(api_key_header)):
    if key != "my-secret-api-key":
        raise HTTPException(status_code=401, detail="Invalid API key")
    return key

@app.get("/api-key-protected")
def protected(key: str = Depends(verify_api_key)):
    return {"message": "Access granted via API key"}

# JWT auth
oauth2 = OAuth2PasswordBearer(tokenUrl="/login")

def create_token(data: dict, expires: timedelta = timedelta(hours=1)):
    payload = data.copy()
    payload["exp"] = datetime.utcnow() + expires
    return jwt.encode(payload, SECRET, algorithm="HS256")

def get_current_user(token: str = Depends(oauth2)):
    try:
        payload = jwt.decode(token, SECRET, algorithms=["HS256"])
        return {"user": payload["sub"], "role": payload.get("role", "user")}
    except JWTError:
        raise HTTPException(status_code=401, detail="Invalid token")

@app.post("/login")
def login(username: str, password: str):
    if username == "admin" and password == "pass":
        token = create_token({"sub": username, "role": "admin"})
        return {"access_token": token, "token_type": "bearer"}
    raise HTTPException(status_code=401, detail="Bad credentials")

@app.get("/jwt-protected")
def jwt_protected(user: dict = Depends(get_current_user)):
    return {"message": f"Hello {user['user']}"}
