from fastapi import FastAPI, HTTPException, Query
from pydantic import BaseModel, Field
from typing import Optional
from datetime import datetime

app = FastAPI(title="E-Commerce API", version="1.0.0")

# Consistent response model
class ApiResponse(BaseModel):
    data: dict | list | None = None
    error: Optional[str] = None
    meta: Optional[dict] = None

class OrderCreate(BaseModel):
    product_id: int
    quantity: int = Field(gt=0, le=100)
    note: Optional[str] = Field(None, max_length=500)

orders_db: dict[int, dict] = {}

# Nouns, plural, nested resources
@app.get("/v1/users/{user_id}/orders")
def list_user_orders(
    user_id: int,
    status: Optional[str] = Query(None, pattern="^(pending|shipped|delivered)$"),
    limit: int = Query(20, ge=1, le=100),
    offset: int = Query(0, ge=0)
):
    user_orders = [o for o in orders_db.values() if o["user_id"] == user_id]
    if status:
        user_orders = [o for o in user_orders if o["status"] == status]
    return ApiResponse(
        data=user_orders[offset:offset + limit],
        meta={"total": len(user_orders), "limit": limit, "offset": offset}
    )

@app.post("/v1/users/{user_id}/orders", status_code=201)
def create_order(user_id: int, order: OrderCreate):
    order_id = len(orders_db) + 1
    orders_db[order_id] = {
        "id": order_id,
        "user_id": user_id,
        "product_id": order.product_id,
        "quantity": order.quantity,
        "status": "pending",
        "created_at": datetime.now().isoformat()
    }
    return ApiResponse(data=orders_db[order_id])

# Consistent error format
@app.exception_handler(HTTPException)
async def custom_error(request, exc):
    from fastapi.responses import JSONResponse
    return JSONResponse(
        status_code=exc.status_code,
        content={"data": None, "error": exc.detail, "meta": None}
    )
